#!/usr/bin/env node
/**
 * publish-bundles.js — markdown source of truth → signed cohort.surface
 * bundles POSTed to swf-node.
 *
 * For each record under cohort-data/{teams,people,clusters}/*.md:
 *   1. Parse frontmatter
 *   2. Extract surface fields per cohort-data/schema.yml
 *   3. GET /bundles?kind=cohort.surface&record_id=<id> to find current max version
 *   4. Skip if remote payload matches local (avoids version churn)
 *   5. Otherwise wrap in spec §3.1 envelope, sign with our Ed25519 alchemist key, POST /bundles
 *
 * Usage:
 *   node scripts/publish-bundles.js                       # publish all (full pass)
 *   node scripts/publish-bundles.js --only=pramaana       # one record
 *   node scripts/publish-bundles.js --dry-run             # show what would change
 *   node scripts/publish-bundles.js --id=<alchemist-id>   # use a different signing key
 *   node scripts/publish-bundles.js --server=<url>        # default http://127.0.0.1:7777
 *
 * Requires: an Ed25519 keypair generated by `node scripts/keys-gen.js`,
 * and that swf-node is running with the matching pubkey loaded in
 * .alchemists.yml. Restart swf-node after generating new keys.
 */
const fs   = require("node:fs");
const path = require("node:path");
const os   = require("node:os");
const crypto = require("node:crypto");
const yaml = require("js-yaml");

// ── args ─────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
const arg = (name, dflt = null) => {
  const eq = args.find(a => a.startsWith(`--${name}=`));
  if (eq) return eq.slice(name.length + 3);
  const i = args.indexOf(`--${name}`);
  if (i >= 0 && args[i + 1] && !args[i + 1].startsWith("--")) return args[i + 1];
  return dflt;
};
const flag = (name) => args.includes(`--${name}`);

const SERVER       = (arg("server") || "http://127.0.0.1:7777").replace(/\/+$/, "");
const ONLY         = arg("only");
const DRY_RUN      = flag("dry-run");

const REPO_ROOT  = path.resolve(__dirname, "..");
const COHORT_DIR = path.join(REPO_ROOT, "cohort-data");
const PRIV_DIR   = path.join(COHORT_DIR, ".private");

// Resolve alchemist id: --id wins; else if exactly one .ed25519.json
// exists in cohort-data/.private/, use that; else fall back to OS user.
function resolveAlchemistId() {
  const explicit = arg("id");
  if (explicit) return explicit;
  if (fs.existsSync(PRIV_DIR)) {
    const keys = fs.readdirSync(PRIV_DIR).filter(f => f.endsWith(".ed25519.json"));
    if (keys.length === 1) return keys[0].replace(/\.ed25519\.json$/, "");
    if (keys.length > 1) {
      console.error(`[publish] multiple keys found in ${PRIV_DIR}; pass --id=<one-of>`);
      console.error(`          available: ${keys.map(k => k.replace(/\.ed25519\.json$/, "")).join(", ")}`);
      process.exit(2);
    }
  }
  return os.userInfo().username || "alchemist";
}
const ALCHEMIST_ID = resolveAlchemistId();
const PRIV_FILE    = path.join(PRIV_DIR, `${ALCHEMIST_ID}.ed25519.json`);

// ── load signing key ─────────────────────────────────────────────────
// Two formats supported:
//   • cohort-data/.private/<id>.ed25519.json  (created by keys-gen.js)
//   • a PEM file passed via --pem=<path>  (PKCS8 Ed25519, e.g. ssh-keygen
//     output) — useful when you want to reuse an existing keyset like the
//     alchemist-NN.pem files the parallel alchemist Claude generates.
function loadSigningKey() {
  const pemPath = arg("pem");
  if (pemPath) {
    if (!fs.existsSync(pemPath)) {
      console.error(`[publish] PEM not found: ${pemPath}`);
      process.exit(2);
    }
    const privateKey = crypto.createPrivateKey(fs.readFileSync(pemPath));
    const pubObj = crypto.createPublicKey(privateKey);
    const jwk = pubObj.export({ format: "jwk" });
    const pubHex = Buffer.from(jwk.x, "base64url").toString("hex");
    return { privateKey, pubkeyField: `ed25519:${pubHex}` };
  }
  if (!fs.existsSync(PRIV_FILE)) {
    console.error(`[publish] no private key at ${PRIV_FILE}`);
    console.error(`[publish] either: node scripts/keys-gen.js ${ALCHEMIST_ID}`);
    console.error(`[publish] or: pass --pem=<path-to-existing-pem>`);
    process.exit(2);
  }
  const j = JSON.parse(fs.readFileSync(PRIV_FILE, "utf8"));
  // Node createPrivateKey from JWK needs both d (seed) and x (pubkey).
  // We have seed_b64u and pubkey "ed25519:<hex>". Convert hex → base64url.
  const pubHex = j.pubkey.replace(/^ed25519:/, "");
  const xB64u = Buffer.from(pubHex, "hex").toString("base64url");
  const privateKey = crypto.createPrivateKey({
    key: { kty: "OKP", crv: "Ed25519", d: j.seed_b64u, x: xB64u },
    format: "jwk",
  });
  return { privateKey, pubkeyField: j.pubkey };
}

// ── markdown frontmatter parsing (mirrors build-bundles.js) ──────────
function readSchema() {
  const p = path.join(COHORT_DIR, "schema.yml");
  if (!fs.existsSync(p)) throw new Error(`schema.yml not found at ${p}`);
  return yaml.load(fs.readFileSync(p, "utf8"));
}
function parseMarkdown(file) {
  const raw = fs.readFileSync(file, "utf8").replace(/\r\n?/g, "\n");
  const m = /^---\n([\s\S]*?)\n---\n?([\s\S]*)$/.exec(raw);
  if (!m) return { frontmatter: null, body: raw };
  let fm;
  try { fm = yaml.load(m[1]); }
  catch (e) { throw new Error(`bad YAML in ${file}: ${e.message}`); }
  return { frontmatter: fm, body: m[2] };
}
function pickSurface(obj, whitelist) {
  const out = {};
  for (const k of whitelist) {
    if (Object.prototype.hasOwnProperty.call(obj || {}, k)) out[k] = obj[k];
  }
  return out;
}

function loadAllRecords() {
  const schema = readSchema();
  if (schema.schema_version !== 1) {
    throw new Error(`unsupported schema_version in ${path.join(COHORT_DIR, "schema.yml")}`);
  }
  const out = []; // [{ kind: "cohort.surface", record_id, payload }]
  for (const [type, dir, sf] of [
    ["team",    "teams",    schema.teams?.surface_fields    || []],
    ["person",  "people",   schema.people?.surface_fields   || []],
    ["cluster", "clusters", schema.clusters?.surface_fields || []],
  ]) {
    const d = path.join(COHORT_DIR, dir);
    if (!fs.existsSync(d)) continue;
    for (const f of fs.readdirSync(d)) {
      if (!f.endsWith(".md")) continue;
      const fp = path.join(d, f);
      const { frontmatter } = parseMarkdown(fp);
      if (!frontmatter || frontmatter.record_type !== type || !frontmatter.record_id) continue;
      const payload = pickSurface(frontmatter, sf);
      out.push({ record_id: frontmatter.record_id, payload, _file: fp });
    }
  }
  return out;
}

// ── canonical JSON (must match swf-node's Python:
//    json.dumps(sort_keys=True, separators=(",", ":"), ensure_ascii=False) ──
function canonical(v) {
  if (v === null) return "null";
  if (v === undefined) return "null"; // shouldn't happen in our schema
  // js-yaml parses YYYY-MM-DD strings as JS Date instances. Without
  // this branch, Date falls through to the object case and serializes
  // as `{}` (Dates have no enumerable own properties) — which was the
  // bug that wiped dates_start / dates_end / absences from the wire.
  if (v instanceof Date) {
    if (Number.isNaN(v.getTime())) throw new Error(`invalid Date in payload`);
    return JSON.stringify(v.toISOString().slice(0, 10));   // YYYY-MM-DD
  }
  if (typeof v === "number") {
    if (!Number.isFinite(v)) throw new Error(`non-finite number in payload`);
    return JSON.stringify(v);
  }
  if (typeof v === "string" || typeof v === "boolean") return JSON.stringify(v);
  if (Array.isArray(v)) return `[${v.map(canonical).join(",")}]`;
  if (typeof v === "object") {
    const keys = Object.keys(v).sort();
    return `{${keys.map(k => `${JSON.stringify(k)}:${canonical(v[k])}`).join(",")}}`;
  }
  throw new Error(`unsupported type in payload: ${typeof v}`);
}

// ── envelope build + sign ────────────────────────────────────────────
function buildEnvelope({ recordId, version, payload, pubkeyField, privateKey }) {
  const payloadB64 = Buffer.from(canonical(payload), "utf8").toString("base64");
  const env = {
    magic: "swf-bundle-v1",
    kind: "cohort.surface",
    record_id: recordId,
    version,
    author: {
      pubkey: pubkeyField,
      signed_at: new Date().toISOString(),
    },
    encryption: null,
    payload: payloadB64,
  };
  // Sign over the canonical envelope minus the (yet-to-be-added) signature.
  const msg = Buffer.from(canonical(env), "utf8");
  const sigBuf = crypto.sign(null, msg, privateKey);
  env.signature = sigBuf.toString("hex");
  return env;
}

// ── swf-node round-trip helpers ──────────────────────────────────────
async function ghttp(method, url, body) {
  const res = await fetch(`${SERVER}${url}`, {
    method,
    headers: body ? { "Content-Type": "application/json" } : {},
    body: body ? JSON.stringify(body) : undefined,
  });
  const text = await res.text();
  let json = null;
  if (text) { try { json = JSON.parse(text); } catch {} }
  return { status: res.status, ok: res.ok, json, text };
}

async function getCurrentBundle(recordId) {
  // Pull all cohort.surface bundles for this record_id; pick the highest version.
  const r = await ghttp("GET", `/bundles?kind=cohort.surface&record_id=${encodeURIComponent(recordId)}`);
  if (!r.ok) return null;
  const list = (r.json && Array.isArray(r.json.bundles)) ? r.json.bundles : [];
  if (list.length === 0) return null;
  return list.reduce((best, b) => (b.version > (best?.version ?? -1) ? b : best), null);
}

function payloadOf(envelope) {
  if (!envelope || !envelope.payload) return null;
  try {
    const decoded = Buffer.from(envelope.payload, "base64").toString("utf8");
    return JSON.parse(decoded);
  } catch { return null; }
}

function deepEqualCanonical(a, b) {
  return canonical(a) === canonical(b);
}

// ── main ─────────────────────────────────────────────────────────────
async function main() {
  const { privateKey, pubkeyField } = loadSigningKey();
  let records = loadAllRecords();
  if (ONLY) records = records.filter(r => r.record_id === ONLY);
  if (records.length === 0) {
    console.error(`[publish] no records to publish (only=${ONLY || "*"})`);
    process.exit(1);
  }

  console.log(`[publish] target: ${SERVER}`);
  console.log(`[publish] signing as: ${pubkeyField} (${ALCHEMIST_ID})`);
  console.log(`[publish] records: ${records.length}${DRY_RUN ? " · DRY RUN" : ""}`);

  let pushed = 0, skipped = 0, failed = 0;
  for (const rec of records) {
    const current = await getCurrentBundle(rec.record_id);
    const currentPayload = payloadOf(current);
    if (current && currentPayload && deepEqualCanonical(currentPayload, rec.payload)) {
      console.log(`  · ${rec.record_id.padEnd(18)} v${current.version} unchanged · skip`);
      skipped++;
      continue;
    }
    const nextVersion = current ? current.version + 1 : 1;
    const env = buildEnvelope({
      recordId: rec.record_id,
      version: nextVersion,
      payload: rec.payload,
      pubkeyField,
      privateKey,
    });
    if (DRY_RUN) {
      console.log(`  ↑ ${rec.record_id.padEnd(18)} v${nextVersion} (${current ? "update" : "create"}) · dry`);
      pushed++;
      continue;
    }
    const post = await ghttp("POST", `/bundles`, env);
    if (post.ok) {
      console.log(`  ↑ ${rec.record_id.padEnd(18)} v${nextVersion} (${current ? "update" : "create"}) · cid=${post.json?.cid?.slice(0, 12) || "?"}`);
      pushed++;
    } else {
      console.error(`  ✗ ${rec.record_id.padEnd(18)} HTTP ${post.status} · ${(post.json?.error || post.text || "").slice(0, 200)}`);
      failed++;
    }
  }
  console.log(`[publish] done · pushed=${pushed} skipped=${skipped} failed=${failed}`);
  if (failed > 0) process.exit(4);
}

main().catch(e => { console.error("[publish] fatal:", e); process.exit(99); });
